[CmdletBinding(SupportsShouldProcess=$true)]
param([switch]$ClearOfficeIdentityCache,[switch]$ResetOutlookNavigation,[switch]$RepairOfficeService,[switch]$RebuildSearchIndex,[switch]$Force,[string]$OutputPath="$env:USERPROFILE\Desktop\M365OutlookRepair")
$ErrorActionPreference='Stop';New-Item -ItemType Directory -Path $OutputPath -Force|Out-Null;$Log=Join-Path $OutputPath ("repair-{0:yyyyMMdd-HHmmss}.log"-f(Get-Date));function L($m){"$(Get-Date -Format s) $m"|Tee-Object -FilePath $Log -Append};function Admin{$p=[Security.Principal.WindowsPrincipal][Security.Principal.WindowsIdentity]::GetCurrent();$p.IsInRole([Security.Principal.WindowsBuiltInRole]::Administrator)}
if(-not($ClearOfficeIdentityCache-or$ResetOutlookNavigation-or$RepairOfficeService-or$RebuildSearchIndex)){throw'Choose at least one repair action.'}
$office=Get-Process outlook,winword,excel,powerpnt,ms-teams -ErrorAction SilentlyContinue;if($office-and-not$Force){throw'Close Office apps or use -Force.'};if($office){$office|Stop-Process -Force}
if($ClearOfficeIdentityCache){$paths=@("$env:LOCALAPPDATA\Microsoft\OneAuth","$env:LOCALAPPDATA\Microsoft\IdentityCache");foreach($p in $paths){if(Test-Path $p){Copy-Item $p (Join-Path $OutputPath (Split-Path $p -Leaf)) -Recurse -Force -ErrorAction SilentlyContinue;if($PSCmdlet.ShouldProcess($p,'Clear Office identity cache')){Remove-Item $p -Recurse -Force}}};L'Office identity cache cleared.'}
if($ResetOutlookNavigation){$outlook=(Get-Command outlook.exe -ErrorAction SilentlyContinue).Source;if(-not$outlook){$outlook=Get-ChildItem "$env:ProgramFiles\Microsoft Office" -Filter OUTLOOK.EXE -Recurse -ErrorAction SilentlyContinue|Select-Object -First 1 -Expand FullName};if(-not$outlook){throw'Outlook.exe not found.'};if($PSCmdlet.ShouldProcess('Outlook','Reset navigation pane')){Start-Process $outlook '/resetnavpane';L'Outlook navigation reset launched.'}}
if($RepairOfficeService){if(-not(Admin)){throw'Administrator rights required.'};if(Get-Service ClickToRunSvc -ErrorAction SilentlyContinue){if($PSCmdlet.ShouldProcess('ClickToRunSvc','Restart service')){Restart-Service ClickToRunSvc -Force;L'Click-to-Run service restarted.'}}else{throw'ClickToRunSvc not found.'}}
if($RebuildSearchIndex){if(-not(Admin)){throw'Administrator rights required.'};if($PSCmdlet.ShouldProcess('Windows Search','Restart service and request index rebuild')){Stop-Service WSearch -Force;Remove-Item "$env:ProgramData\Microsoft\Search\Data\Applications\Windows\Windows.edb" -Force -ErrorAction SilentlyContinue;Start-Service WSearch;L'Search index rebuild requested.'}}
L'Repair workflow finished.'